import {
  expect,
  Page,
  PageAssertionsToHaveScreenshotOptions,
  test,
} from '@playwright/test';

test.describe('public', () => {
  test('/auth/recover-callback', async ({ page }) => {
    await page.goto('/auth/recover-callback');
    await expect(page).toHaveScreenshot();
  });

  test('/auth/recover', async ({ page }) => {
    await page.goto('/auth/recover');
    await expect(page).toHaveScreenshot();
  });

  test('/auth/reset-password', async ({ page }) => {
    await page.goto('/auth/reset-password');
    await expect(page).toHaveScreenshot();
  });

  test('/auth/signin', async ({ page }) => {
    await page.goto('/auth/signin');
    await expect(page).toHaveScreenshot();
  });

  test('/auth/signup', async ({ page }) => {
    await page.goto('/auth/signup');
    await expect(page).toHaveScreenshot();
  });
});

function consoleScreenShotOptions(
  page: Page,
): PageAssertionsToHaveScreenshotOptions {
  return {
    fullPage: true,
    mask: [page.locator('.develop')],
  };
}

test.describe('super_admin', () => {
  test.use({ storageState: 'playwright/.auth/super_admin.json' });

  test('/super-admin/teams', async ({ page }) => {
    await page.goto('/super-admin/teams');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    // TeamCreationModal
    await page
      .getByRole('button', { name: 'Create New Team' })
      .click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'CANCEL' }).click();

    const targetTeamId = 'ac100000-0001-0000-0000-000000000000';
    // CurrentTeamPlan
    await page
      .getByRole('table')
      .getByRole('row')
      // Select active teams
      .filter({ has: page.getByText(targetTeamId) })
      .getByRole('button')
      .first()
      .click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page)); // SS of Menu
    await page.getByRole('menuitem', { name: 'Current' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // NextTeamPlan
    await page
      .getByRole('table')
      .getByRole('row')
      // Select active teams
      .filter({ has: page.getByText(targetTeamId) })
      .getByRole('button')
      .first()
      .click();
    await page.getByRole('menuitem', { name: 'Next' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // Plan Details
    await page
      .getByRole('table')
      .getByRole('row')
      // Select active teams
      .filter({ has: page.getByText(targetTeamId) })
      .getByRole('button')
      .first()
      .click();
    await page.getByRole('menuitem', { name: 'Details' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/super-admin/notifications', async ({ page }) => {
    await page.goto('/super-admin/notifications');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    // NotificationCreationPage
    await page.goto('/super-admin/notifications/new');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });
});

test.describe('team_admin', () => {
  test.use({ storageState: 'playwright/.auth/team_admin.json' });

  test('/account', async ({ page }) => {
    await page.goto('/account');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    await page.getByRole('tab', { name: 'TEAM' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    await page.getByRole('tab', { name: 'PASSWORD' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/account/edit', async ({ page }) => {
    await page.goto('/account/edit');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    await page.getByRole('tab', { name: 'TEAM' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    await page.getByRole('tab', { name: 'PASSWORD' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/notifications', async ({ page }) => {
    await page.goto('/notifications');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/terms-of-use', async ({ page }) => {
    await page.goto('/terms-of-use');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/privacy-policy', async ({ page }) => {
    await page.goto('/privacy-policy');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/teams/[team_id]/admin', async ({ page }) => {
    await page.goto('/teams/a0000000-0000-0000-0000-000000000000/admin');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    const targetUserName = 'adm1-team_a';
    // EditProfileModal
    await page
      .getByRole('table')
      .getByRole('row')
      .filter({ has: page.getByText(targetUserName) })
      .getByRole('button')
      .first()
      .click();
    await page.getByRole('menuitem', { name: 'EDIT' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'DISCARD' }).click();
    // InviteProfileModal
    await page.getByRole('button', { name: 'INVITE MEMBER' }).first().click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/teams/[team_id]/team-plans', async ({ page }, testInfo) => {
    const isMobile = testInfo.project.name.includes('Mobile Chrome');
    await page.goto('/teams/a0000000-0000-0000-0000-000000000000/team-plans');
    if (isMobile) {
      await page.waitForSelector('.MuiGrid2-root');
    } else {
      await page.waitForSelector('.MuiTable-root');
    }
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/teams/[team_id]/players', async ({ page }, testInfo) => {
    const isMobile = testInfo.project.name.includes('Mobile Chrome');
    await page.goto('/teams/a0000000-0000-0000-0000-000000000000/players');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    // CreatePlayerModal
    await page
      .getByRole('button', { name: 'CREATE NEW PLAYER' })
      .first()
      .click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // DeletePlayerModal
    const targetPlayerName1 = 'ply2-mgr1-team_a';
    if (isMobile) {
      await page
        .locator('.MuiPaper-root')
        .locator('.MuiStack-root')
        .locator('.MuiPaper-root')
        .filter({ has: page.getByText(targetPlayerName1) }) // Select deletable player.
        .getByRole('button')
        .first()
        .click();
    } else {
      await page
        .getByRole('table')
        .getByRole('row')
        .filter({ has: page.getByText(targetPlayerName1) }) // Select deletable player.
        .getByRole('button')
        .first()
        .click();
    }
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page)); // SS of Menu
    await page.getByRole('menuitem', { name: 'DELETE' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // EditPlayerModal
    const targetPlayerName2 = 'ply1-adm1-team_a';
    if (isMobile) {
      await page
        .locator('.MuiPaper-root')
        .locator('.MuiStack-root')
        .locator('.MuiPaper-root')
        .filter({ has: page.getByText(targetPlayerName2) })
        .getByRole('button')
        .first()
        .click();
    } else {
      await page.getByRole('table').getByRole('button').first().click();
    }
    await page.getByRole('menuitem', { name: 'EDIT' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/teams/[team_id]/sessions/[session_id]/resources/[resource_id]', async ({
    page,
  }) => {
    await page.setViewportSize({ width: 1280, height: 1720 });
    await page.goto(
      // eslint-disable-next-line max-len
      '/teams/a0000000-0000-0000-0000-000000000000/sessions/a0000000-0001-0001-0000-000000000000/resources/a0000000-0001-0001-0001-000000000000',
    );
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/teams/[team_id]/sessions/[session_id]/resources', async ({
    page,
  }, testInfo) => {
    const isMobile = testInfo.project.name.includes('Mobile Chrome');
    await page.goto(
      '/teams/a0000000-0000-0000-0000-000000000000/sessions/a0000000-0001-0001-0000-000000000000/resources',
    );
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    await page.waitForLoadState('networkidle');

    // FileUploadModal
    await page
      .getByRole('button', { name: 'Upload Video' })
      .click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // SessionUpdateModal
    await page.getByRole('button', { name: 'EDIT' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'CANCEL' }).click();

