import {
  expect,
  Page,
  PageAssertionsToHaveScreenshotOptions,
  test,
  TestInfo,
} from '@playwright/test';

/**
 * テスト用の定数
 */
const TEST_DATA = {
  TEAM_ID: 'a0000000-0000-0000-0000-000000000000',
  TARGET_TEAM_ID: 'ac100000-0001-0000-0000-000000000000',
  SESSION_ID: 'a0000000-0001-0001-0000-000000000000',
  RESOURCE_ID: 'a0000000-0001-0001-0001-000000000000',
  TEST_USER_NAME: 'adm1-team_a',
  DELETABLE_PLAYER_NAME: 'ply2-mgr1-team_a',
  EDITABLE_PLAYER_NAME: 'ply1-adm1-team_a',
} as const;

/**
 * スクリーンショットオプション: フルページで開発環境表示をマスク
 */
function getScreenshotOptions(
  page: Page,
): PageAssertionsToHaveScreenshotOptions {
  return {
    fullPage: true,
    mask: [page.locator('.develop')],
  };
}

/**
 * ヘルパー関数: スクリーンショットを撮影
 */
async function takeScreenshot(page: Page): Promise<void> {
  await expect(page).toHaveScreenshot(getScreenshotOptions(page));
}

/**
 * ヘルパー関数: モバイルかどうかを判定
 */
function isMobileDevice(testInfo: TestInfo): boolean {
  return testInfo.project.name.includes('Mobile Chrome');
}

/**
 * 公開ページ（未認証）のVRT
 */
test.describe('public', () => {
  const publicPages = [
    '/auth/recover-callback',
    '/auth/recover',
    '/auth/reset-password',
    '/auth/signin',
    '/auth/signup',
  ];

  for (const pagePath of publicPages) {
    test(pagePath, async ({ page }) => {
      await page.goto(pagePath);
      await expect(page).toHaveScreenshot();
    });
  }
});

/**
 * スーパー管理者画面のVRT
 */
test.describe('super_admin', () => {
  test.use({ storageState: 'playwright/.auth/super_admin.json' });

  test('/super-admin/teams - チーム管理画面とモーダル表示', async ({
    page,
  }) => {
    // 初期表示
    await page.goto('/super-admin/teams');
    await takeScreenshot(page);

    // チーム作成モーダルの表示確認
    await page.getByRole('button', { name: 'Create New Team' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // 現在のプラン表示モーダル
    await openTeamActionMenu(page, TEST_DATA.TARGET_TEAM_ID);
    await takeScreenshot(page); // メニュー表示
    await page.getByRole('menuitem', { name: 'Current' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // 次のプラン表示モーダル
    await openTeamActionMenu(page, TEST_DATA.TARGET_TEAM_ID);
    await page.getByRole('menuitem', { name: 'Next' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // プラン詳細モーダル
    await openTeamActionMenu(page, TEST_DATA.TARGET_TEAM_ID);
    await page.getByRole('menuitem', { name: 'Details' }).click();
    await takeScreenshot(page);
  });

  test('/super-admin/notifications - 通知管理画面', async ({ page }) => {
    // 通知一覧
    await page.goto('/super-admin/notifications');
    await takeScreenshot(page);

    // 通知作成ページ
    await page.goto('/super-admin/notifications/new');
    await takeScreenshot(page);
  });
});

/**
 * ヘルパー関数: チームアクションメニューを開く
 */
async function openTeamActionMenu(page: Page, teamId: string): Promise<void> {
  await page
    .getByRole('table')
    .getByRole('row')
    .filter({ has: page.getByText(teamId) })
    .getByRole('button')
    .first()
    .click();
}

/**
 * ヘルパー関数: ユーザーアクションメニューを開く
 */
async function openUserActionMenu(
  page: Page,
  userName: string,
): Promise<void> {
  await page
    .getByRole('table')
    .getByRole('row')
    .filter({ has: page.getByText(userName) })
    .getByRole('button')
    .first()
    .click();
}

/**
 * ヘルパー関数: プレイヤーアクションメニューを開く（モバイル対応）
 */
async function openPlayerActionMenu(
  page: Page,
  playerName: string,
  isMobile: boolean,
): Promise<void> {
  if (isMobile) {
    await page
      .locator('.MuiPaper-root')
      .locator('.MuiStack-root')
      .locator('.MuiPaper-root')
      .filter({ has: page.getByText(playerName) })
      .getByRole('button')
      .first()
      .click();
  } else {
    await page
      .getByRole('table')
      .getByRole('row')
      .filter({ has: page.getByText(playerName) })
      .getByRole('button')
      .first()
      .click();
  }
}

