import {
  expect,
  Page,
  PageAssertionsToHaveScreenshotOptions,
  test,
  TestInfo,
} from '@playwright/test';

/**
 * テスト用の定数
 */
const TEST_DATA = {
  TEAM_ID: 'a0000000-0000-0000-0000-000000000000',
  TARGET_TEAM_ID: 'ac100000-0001-0000-0000-000000000000',
  SESSION_ID: 'a0000000-0001-0001-0000-000000000000',
  RESOURCE_ID: 'a0000000-0001-0001-0001-000000000000',
  TEST_USER_NAME: 'adm1-team_a',
  DELETABLE_PLAYER_NAME: 'ply2-mgr1-team_a',
  EDITABLE_PLAYER_NAME: 'ply1-adm1-team_a',
} as const;

/**
 * スクリーンショットオプション: フルページで開発環境表示をマスク
 */
function getScreenshotOptions(
  page: Page,
): PageAssertionsToHaveScreenshotOptions {
  return {
    fullPage: true,
    mask: [page.locator('.develop')],
  };
}

/**
 * ヘルパー関数: スクリーンショットを撮影
 */
async function takeScreenshot(page: Page): Promise<void> {
  await expect(page).toHaveScreenshot(getScreenshotOptions(page));
}

/**
 * ヘルパー関数: モバイルかどうかを判定
 */
function isMobileDevice(testInfo: TestInfo): boolean {
  return testInfo.project.name.includes('Mobile Chrome');
}

/**
 * 公開ページ（未認証）のVRT
 */
test.describe('public', () => {
  const publicPages = [
    '/auth/recover-callback',
    '/auth/recover',
    '/auth/reset-password',
    '/auth/signin',
    '/auth/signup',
  ];

  for (const pagePath of publicPages) {
    test(pagePath, async ({ page }) => {
      await page.goto(pagePath);
      await expect(page).toHaveScreenshot();
    });
  }
});

/**
 * スーパー管理者画面のVRT
 */
test.describe('super_admin', () => {
  test.use({ storageState: 'playwright/.auth/super_admin.json' });

  test('/super-admin/teams - チーム管理画面とモーダル表示', async ({
    page,
  }) => {
    // 初期表示
    await page.goto('/super-admin/teams');
    await takeScreenshot(page);

    // チーム作成モーダルの表示確認
    await page.getByRole('button', { name: 'Create New Team' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // 現在のプラン表示モーダル
    await openTeamActionMenu(page, TEST_DATA.TARGET_TEAM_ID);
    await takeScreenshot(page); // メニュー表示
    await page.getByRole('menuitem', { name: 'Current' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // 次のプラン表示モーダル
    await openTeamActionMenu(page, TEST_DATA.TARGET_TEAM_ID);
    await page.getByRole('menuitem', { name: 'Next' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // プラン詳細モーダル
    await openTeamActionMenu(page, TEST_DATA.TARGET_TEAM_ID);
    await page.getByRole('menuitem', { name: 'Details' }).click();
    await takeScreenshot(page);
  });

  test('/super-admin/notifications - 通知管理画面', async ({ page }) => {
    // 通知一覧
    await page.goto('/super-admin/notifications');
    await takeScreenshot(page);

    // 通知作成ページ
    await page.goto('/super-admin/notifications/new');
    await takeScreenshot(page);
  });
});

/**
 * ヘルパー関数: チームアクションメニューを開く
 */
async function openTeamActionMenu(page: Page, teamId: string): Promise<void> {
  await page
    .getByRole('table')
    .getByRole('row')
    .filter({ has: page.getByText(teamId) })
    .getByRole('button')
    .first()
    .click();
}

/**
 * ヘルパー関数: ユーザーアクションメニューを開く
 */
async function openUserActionMenu(
  page: Page,
  userName: string,
): Promise<void> {
  await page
    .getByRole('table')
    .getByRole('row')
    .filter({ has: page.getByText(userName) })
    .getByRole('button')
    .first()
    .click();
}

/**
 * ヘルパー関数: プレイヤーアクションメニューを開く（モバイル対応）
 */
async function openPlayerActionMenu(
  page: Page,
  playerName: string,
  isMobile: boolean,
): Promise<void> {
  if (isMobile) {
    await page
      .locator('.MuiPaper-root')
      .locator('.MuiStack-root')
      .locator('.MuiPaper-root')
      .filter({ has: page.getByText(playerName) })
      .getByRole('button')
      .first()
      .click();
  } else {
    await page
      .getByRole('table')
      .getByRole('row')
      .filter({ has: page.getByText(playerName) })
      .getByRole('button')
      .first()
      .click();
  }
}

/**
 * ヘルパー関数: セッションアクションメニューを開く（モバイル対応）
 */
async function openSessionActionMenu(
  page: Page,
  isMobile: boolean,
): Promise<void> {
  if (isMobile) {
    await page
      .locator('.MuiGrid2-root')
      .locator('.MuiGrid2-root')
      .locator('.MuiPaper-root')
      .locator('.MuiBox-root')
      .getByRole('button')
      .first()
      .click();
  } else {
    await page.getByRole('table').getByRole('button').first().click();
  }
}

/**
 * チーム管理者画面のVRT
 */
test.describe('team_admin', () => {
  test.use({ storageState: 'playwright/.auth/team_admin.json' });

  test('/account - アカウント設定ページの各タブ', async ({ page }) => {
    await page.goto('/account');
    await takeScreenshot(page);

    // チームタブ
    await page.getByRole('tab', { name: 'TEAM' }).click();
    await takeScreenshot(page);

    // パスワードタブ
    await page.getByRole('tab', { name: 'PASSWORD' }).click();
    await takeScreenshot(page);
  });

  test('/account/edit - アカウント編集ページの各タブ', async ({ page }) => {
    await page.goto('/account/edit');
    await takeScreenshot(page);

    // チームタブ
    await page.getByRole('tab', { name: 'TEAM' }).click();
    await takeScreenshot(page);

    // パスワードタブ
    await page.getByRole('tab', { name: 'PASSWORD' }).click();
    await takeScreenshot(page);
  });

  test('/notifications - 通知ページ', async ({ page }) => {
    await page.goto('/notifications');
    await takeScreenshot(page);
  });

  test('/terms-of-use - 利用規約ページ', async ({ page }) => {
    await page.goto('/terms-of-use');
    await takeScreenshot(page);
  });

  test('/privacy-policy - プライバシーポリシーページ', async ({ page }) => {
    await page.goto('/privacy-policy');
    await takeScreenshot(page);
  });

  test('/teams/[team_id]/admin - チーム管理者ページとメンバー管理', async ({
    page,
  }) => {
    await page.goto(`/teams/${TEST_DATA.TEAM_ID}/admin`);
    await takeScreenshot(page);

    // メンバー編集モーダル
    await openUserActionMenu(page, TEST_DATA.TEST_USER_NAME);
    await page.getByRole('menuitem', { name: 'EDIT' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // メンバー招待モーダル
    await page.getByRole('button', { name: 'INVITE MEMBER' }).first().click();
    await takeScreenshot(page);
  });

  test('/teams/[team_id]/team-plans - チームプラン表示', async (
    { page },
    testInfo,
  ) => {
    await page.goto(`/teams/${TEST_DATA.TEAM_ID}/team-plans`);

    // モバイル・デスクトップで異なる要素を待つ
    if (isMobileDevice(testInfo)) {
      await page.waitForSelector('.MuiGrid2-root');
    } else {
      await page.waitForSelector('.MuiTable-root');
    }

    await takeScreenshot(page);
  });

  test('/teams/[team_id]/players - プレイヤー管理画面とモーダル', async (
    { page },
    testInfo,
  ) => {
    const isMobile = isMobileDevice(testInfo);
    await page.goto(`/teams/${TEST_DATA.TEAM_ID}/players`);
    await takeScreenshot(page);

    // プレイヤー作成モーダル
    await page
      .getByRole('button', { name: 'CREATE NEW PLAYER' })
      .first()
      .click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // プレイヤー削除モーダル
    await openPlayerActionMenu(
      page,
      TEST_DATA.DELETABLE_PLAYER_NAME,
      isMobile,
    );
    await takeScreenshot(page); // メニュー表示
    await page.getByRole('menuitem', { name: 'DELETE' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // プレイヤー編集モーダル
    await openPlayerActionMenu(page, TEST_DATA.EDITABLE_PLAYER_NAME, isMobile);
    await page.getByRole('menuitem', { name: 'EDIT' }).click();
    await takeScreenshot(page);
  });

  test('/teams/[team_id]/sessions/[session_id]/resources/[resource_id] - リソース詳細ページ', async ({
    page,
  }) => {
    await page.setViewportSize({ width: 1280, height: 1720 });
    const resourceUrl = `/teams/${TEST_DATA.TEAM_ID}/sessions/${TEST_DATA.SESSION_ID}/resources/${TEST_DATA.RESOURCE_ID}`;
    await page.goto(resourceUrl);
    await takeScreenshot(page);
  });

  test('/teams/[team_id]/sessions/[session_id]/resources - リソース一覧とモーダル', async ({
    page,
  }, testInfo) => {
    const isMobile = isMobileDevice(testInfo);
    const resourcesUrl = `/teams/${TEST_DATA.TEAM_ID}/sessions/${TEST_DATA.SESSION_ID}/resources`;
    await page.goto(resourcesUrl);
    await takeScreenshot(page);

    await page.waitForLoadState('networkidle');

    // ビデオアップロードモーダル
    await page.getByRole('button', { name: 'Upload Video' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // セッション編集モーダル
    await page.getByRole('button', { name: 'EDIT' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // リソース削除モーダル
    if (isMobile) {
      await page.getByRole('link').getByRole('button').first().click();
    } else {
      await page.getByRole('table').getByRole('button').first().click();
    }
    await takeScreenshot(page); // メニュー表示
    await page.getByRole('menuitem', { name: 'Delete' }).click();
    await takeScreenshot(page);
  });

  test('/teams/[team_id]/sessions - セッション管理画面とモーダル', async (
    { page },
    testInfo,
  ) => {
    const isMobile = isMobileDevice(testInfo);
    await page.goto(`/teams/${TEST_DATA.TEAM_ID}/sessions`);
    await takeScreenshot(page);

    // セッション削除モーダル
    await openSessionActionMenu(page, isMobile);
    await takeScreenshot(page); // メニュー表示
    await page.getByRole('menuitem', { name: 'Delete' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // セッション編集モーダル
    await openSessionActionMenu(page, isMobile);
    await page.getByRole('menuitem', { name: 'Edit' }).click();
    await takeScreenshot(page);
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // セッション作成モーダル
    await page.waitForLoadState('networkidle');
    await page.getByRole('button', { name: 'New Session' }).click();
    await takeScreenshot(page);
  });

  test('/teams/resources - リソース一覧ページ', async ({ page }) => {
    await page.goto('/teams/resources');
    await takeScreenshot(page);
  });
});
